class ReportGenerator {
    private final DatabaseConnection db = new MySQLDatabaseConnection("localhost", 3306, "reports");
    private final EmailSender emailSender = new SmtpEmailSender("smtp.company.com");

    void generateAndSendMonthlyReport(String recipientEmail) {
        List<ReportRow> data = db.query("SELECT * FROM monthly_summary");
        Report report = buildReport(data);
        emailSender.send(recipientEmail, report.toHtml());
    }
}
